<template>
  <div class="mvs-cont">
    <div class="filter-wrap">
      <div class="area-bar">
        <span>地区:</span>
        <ul>
          <li>
            <span :class="{ active: area == '全部' }" @click="area = '全部'"
              >全部</span
            >
          </li>
          <li>
            <span :class="{ active: area == '内地' }" @click="area = '内地'"
              >内地</span
            >
          </li>
          <li>
            <span :class="{ active: area == '港台' }" @click="area = '港台'"
              >港台</span
            >
          </li>
          <li>
            <span :class="{ active: area == '欧美' }" @click="area = '欧美'"
              >欧美</span
            >
          </li>
          <li>
            <span :class="{ active: area == '日本' }" @click="area = '日本'"
              >日本</span
            >
          </li>
        </ul>
      </div>
      <div class="type-bar">
        <span>类型:</span>
        <ul>
          <li>
            <span :class="{ active: type == '全部' }" @click="type = '全部'"
              >全部</span
            >
          </li>
          <li>
            <span :class="{ active: type == '官方版' }" @click="type = '官方版'"
              >官方版</span
            >
          </li>
          <li>
            <span :class="{ active: type == '原声' }" @click="type = '原声'"
              >原声</span
            >
          </li>
          <li>
            <span :class="{ active: type == '现场版' }" @click="type = '现场版'"
              >现场版</span
            >
          </li>
          <li>
            <span
              :class="{ active: type == '网易出品' }"
              @click="type = '网易出品'"
              >网易出品</span
            >
          </li>
        </ul>
      </div>
      <div class="desc-bar">
        <span>排序:</span>
        <ul>
          <li>
            <span
              :class="{ active: desc == '上升最快' }"
              @click="desc = '上升最快'"
              >上升最快</span
            >
          </li>
          <li>
            <span :class="{ active: desc == '最热' }" @click="desc = '最热'"
              >最热</span
            >
          </li>
          <li>
            <span :class="{ active: desc == '最新' }" @click="desc = '最新'"
              >最新</span
            >
          </li>
        </ul>
      </div>
    </div>
    <div class="mvs">
      <div class="items">
        <div class="item" v-for="(item,i) in mvList" :key="i" @click="toMv(item.id)">
          <div class="img-wrap">
            <img :src="item.cover" alt="" />
            <span class="iconfont icon-icon_play_default"></span>
            <div class="num-wrap">
              <div class="iconfont icon-icon_play_default"></div>
              <div class="num">{{item.playCount|getCount}}</div>
            </div>
          </div>
          <div class="info-wrap">
            <div class="name">{{item.name}}</div>
            <div class="singer">{{item.artistName}}</div>
          </div>
        </div>
      </div>
    </div>
    <!-- 分页器 -->
      <el-pagination
        @current-change="handleCurrentChange"
        background
        layout="prev, pager, next"
        :total="total"
        :current-page="page"
        :page-size="5"
        :limit="10"
      >
      </el-pagination>
  </div>
</template>

<script>
import music from "@/api/music"
export default {
  data() {
    return {
      area: "全部",
      type: "官方版",
      desc: "最新",
      // 总条数
      total: 20,
      // 页码
      page: 1,
      mvList:[]
    };
  },
  watch:{
    area(){
      this.page = 1
      this.getNewMvs()
    },
    type(){
      this.page = 1
      this.getNewMvs()
    },
    desc(){
      this.page = 1
      this.getNewMvs()
    }
  },
  methods:{
    handleCurrentChange(index){
      this.page = index
      console.log(index)
      this.getNewMvs()
    },
    toMv(id){
      this.$router.push('/mv?id='+id);
    },
    async getNewMvs(){
      const res = await music.newMvs({
        params:{
          area:this.area,
          type:this.type,
          order:this.desc,
          limit:10,
          offset:(this.page-1)*10
        }
      })
      if(res.count){
        this.total = res.count
      }
      this.mvList = res.data
    }
  },
  created(){
    this.page = 1
    this.getNewMvs()
  }
};
</script>

<style lang="scss" scoped>
.mvs-cont {
  padding-top: 20px;
  font-size: 14px;
  .filter-wrap {
    overflow: hidden;
    .area-bar,
    .type-bar,
    .desc-bar {
      display: flex;
      align-items: center;
      ul {
        display: flex;
        li {
          &:not(:last-child) {
            border-right: 1px solid #f2f2f1;
          }
          span {
            margin: 20px;
            color: gray;
            cursor: pointer;
            padding: 5px 20px;
          }
        }
        .active {
          color: #dd6d60;
          background-color: #fcf6f5;
          border-radius: 20px;
        }
      }
    }
    .type-bar {
      margin: 30px 0;
    }
    .desc-bar {
      margin-bottom: 30px;
    }
  }
  .mvs {
    .items {
      display: flex;
      flex-wrap: wrap;
      .item {
        width: 250px;
        cursor: pointer;
        margin-right: 25px;
        margin-bottom: 30px;
        .img-wrap {
          width: 100%;
          position: relative;
          &:hover {
            .iconfont {
              opacity: 1;
            }
          }
          img {
            width: 100%;
            border-radius: 5px;
          }
          > .icon-icon_play_default {
            position: absolute;
            top: 50%;
            left: 50%;
            -webkit-transform: translate(-50%, -50%);
            transform: translate(-50%, -50%);
            width: 40px;
            height: 40px;
            color: #dd6d60;
            font-size: 20px;
            border-radius: 50%;
            display: -webkit-box;
            display: -ms-flexbox;
            display: flex;
            -webkit-box-align: center;
            -ms-flex-align: center;
            align-items: center;
            -webkit-box-pack: center;
            -ms-flex-pack: center;
            justify-content: center;
            background: rgba(255, 255, 255, 0.8);
            opacity: 0;
          }
          .icon-icon_play_default::before {
            transform: translateX(3px);
          }
          .num-wrap {
            position: absolute;
            right: 0;
            top: 0;
            display: flex;
            align-items: center;
            font-size: 15px;
            padding-right: 5px;
            padding-top: 2px;
            color: orange;
            .icon-icon_play_default {
              margin-right: 3px;
              font-size: 13px;
            }
          }
        }
        .info-wrap {
          .singer {
            font-size: 14px;
            color: #c5c5c5;
          }
        }
      }
    }
  }
}
</style>